#!/usr/bin/env python3
"""Generate the optimized Launch System ERD as an uncompressed draw.io file.

The model targets PostgreSQL 16+.  It intentionally separates immutable facts
and events from mutable workflow aggregates and labels unresolved business
rules instead of silently inventing them.
"""

from __future__ import annotations

import argparse
import math
import re
from dataclasses import dataclass, field
from datetime import datetime, timezone
from pathlib import Path
from typing import Iterable
import xml.etree.ElementTree as ET


@dataclass(frozen=True)
class Node:
    name: str
    module: str
    fields: tuple[str, ...] = ()
    kind: str = "table"  # table, view, module, note
    text: str = ""


@dataclass(frozen=True)
class Rel:
    parent: str
    child: str
    label: str = "1 to 0..*"
    dashed: bool = False


@dataclass
class Page:
    name: str
    subtitle: str
    nodes: list[Node] = field(default_factory=list)
    relations: list[Rel] = field(default_factory=list)
    notes: list[Node] = field(default_factory=list)


def T(name: str, module: str, *fields: str) -> Node:
    return Node(name, module, tuple(fields), "table")


def V(name: str, module: str, *fields: str) -> Node:
    return Node(name, module, tuple(fields), "view")


def M(name: str, module: str, text: str) -> Node:
    return Node(name, module, (), "module", text)


def N(title: str, text: str, module: str = "note") -> Node:
    return Node(title, module, (), "note", text)


