def esc(value: str) -> str:
    from html import escape
    return escape(value, quote=False)


def field_html(value: str) -> str:
    first, _, rest = value.partition(" ")
    colors = {"PK": "#7F2420", "FK": "#1F4E79", "UQ": "#6A1B9A", "CK": "#2F6B2F", "IX": "#555555", "GEN": "#8A4B08"}
    if first in colors:
        return f'<span style="color:{colors[first]};font-weight:700">{first}</span> {esc(rest)}'
    return esc(value)


def node_value(node: Node) -> str:
    fill, stroke, dark = PALETTE.get(node.module, PALETTE["cross"])
    if node.kind == "note":
        return (f'<div style="font-family:Arial;color:{dark};font-size:13px;line-height:1.35">'
                f'<b>{esc(node.name)}</b><br><span style="font-size:11px">{esc(node.text)}</span></div>')
    if node.kind == "module":
        return (f'<div style="font-family:Arial;color:{dark};font-size:15px;line-height:1.35">'
                f'<b>{esc(node.name)}</b><br><span style="font-size:11px">{esc(node.text)}</span></div>')
    label = "VIEW / PROJECTION" if node.kind == "view" else "TABLE"
    field_rows = "<br>".join(field_html(v) for v in node.fields)
    return (f'<div style="font-family:Consolas,Arial;color:#263238;font-size:10px;line-height:1.35">'
            f'<div style="background-color:{fill};color:{dark};font-family:Arial;font-size:13px;padding:5px">'
            f'<b>{esc(node.name)}</b> <span style="font-size:9px">{label}</span></div>'
            f'<div style="padding:7px;text-align:left">{field_rows}</div></div>')


def node_height(node: Node, width: int = 420) -> int:
    if node.kind == "module":
        return 115
    if node.kind == "note":
        lines = max(3, math.ceil((len(node.text) + len(node.name)) / 105))
        return 55 + lines * 18
    chars = 57 if width >= 400 else 48
    lines = sum(max(1, math.ceil(len(f) / chars)) for f in node.fields)
    return 52 + lines * 17 + 14


def add_vertex(root: ET.Element, node_id: str, node: Node, x: int, y: int, w: int, h: int) -> ET.Element:
    fill, stroke, _ = PALETTE.get(node.module, PALETTE["cross"])
    if node.kind == "view":
        fill, stroke = "#F2F2F2", "#9E9E9E"
    style = ("rounded=1;whiteSpace=wrap;html=1;overflow=hidden;shadow=0;"
             f"fillColor={'#FFFFFF' if node.kind == 'table' else fill};strokeColor={stroke};"
             "strokeWidth=1.4;align=left;verticalAlign=top;spacing=0;")
    if node.kind == "note":
        style += "dashed=1;spacing=10;"
    if node.kind == "module":
        style += "spacing=12;"
    cell = ET.SubElement(root, "mxCell", {
        "id": node_id, "value": node_value(node), "style": style,
        "vertex": "1", "parent": "1", "dataKind": node.kind, "dataName": node.name,
    })
    ET.SubElement(cell, "mxGeometry", {"x": str(x), "y": str(y), "width": str(w), "height": str(h), "as": "geometry"})
    return cell


def add_edge(root: ET.Element, edge_id: str, rel: Rel, source_id: str, target_id: str) -> None:
    style = ("edgeStyle=orthogonalEdgeStyle;rounded=0;orthogonalLoop=1;jettySize=auto;html=1;"
             "startArrow=ERone;startFill=0;endArrow=ERmany;endFill=0;strokeWidth=1.1;"
             "strokeColor=#64748B;fontSize=10;labelBackgroundColor=#FFFFFF;")
    if rel.dashed:
        style += "dashed=1;"
    cell = ET.SubElement(root, "mxCell", {
        "id": edge_id, "value": esc(rel.label), "style": style, "edge": "1", "parent": "1",
        "source": source_id, "target": target_id, "dataKind": "relationship",
    })
    ET.SubElement(cell, "mxGeometry", {"relative": "1", "as": "geometry"})


def render_page(diagram: ET.Element, page: Page, page_index: int) -> tuple[int, int, int, int]:
    model = ET.SubElement(diagram, "mxGraphModel", {
        "dx": "1600", "dy": "1000", "grid": "1", "gridSize": "10", "guides": "1",
        "tooltips": "1", "connect": "1", "arrows": "1", "fold": "1", "page": "1",
        "pageScale": "1", "pageWidth": "2600", "pageHeight": "2400", "math": "0", "shadow": "0",
    })
    graph = ET.SubElement(model, "root")
    ET.SubElement(graph, "mxCell", {"id": "0"})
    ET.SubElement(graph, "mxCell", {"id": "1", "parent": "0"})

    title = Node(page.name, "cross", (), "module", page.subtitle)
    add_vertex(graph, f"p{page_index}_title", title, 40, 25, 2520, 72)
    # Make title visually distinct.
    title_cell = graph[-1]
    title_cell.set("style", "rounded=1;whiteSpace=wrap;html=1;fillColor=#EAF0F6;strokeColor=#52677A;strokeWidth=2;align=left;verticalAlign=middle;spacing=14;")

    ids: dict[str, str] = {}
    cols = 5
    card_w, gap_x, gap_y = 420, 85, 55
    start_x, y = 40, 125
    rows = [page.nodes[i:i + cols] for i in range(0, len(page.nodes), cols)]
    counter = 0
    for row in rows:
        heights = [node_height(n, card_w) for n in row]
        row_h = max(heights, default=0)
        for c, (node, h) in enumerate(zip(row, heights)):
            node_id = f"p{page_index}_n{counter}"
            add_vertex(graph, node_id, node, start_x + c * (card_w + gap_x), y, card_w, h)
            if node.name in ids:
                raise ValueError(f"Duplicate node name on page {page.name}: {node.name}")
            ids[node.name] = node_id
            counter += 1
        y += row_h + gap_y

    if page.notes:
        y += 15
        note_w, note_gap = 1215, 90
        for i in range(0, len(page.notes), 2):
            pair = page.notes[i:i + 2]
            heights = [node_height(n, note_w) for n in pair]
            row_h = max(heights)
            for c, (node, h) in enumerate(zip(pair, heights)):
                node_id = f"p{page_index}_note{i+c}"
                add_vertex(graph, node_id, node, 40 + c * (note_w + note_gap), y, note_w, h)
            y += row_h + 35

    for i, rel in enumerate(page.relations):
        if rel.parent not in ids or rel.child not in ids:
            raise ValueError(f"Missing endpoint on {page.name}: {rel.parent} -> {rel.child}")
        add_edge(graph, f"p{page_index}_e{i}", rel, ids[rel.parent], ids[rel.child])

    model.set("pageHeight", str(max(2400, y + 100)))
    tables = sum(n.kind == "table" for n in page.nodes)
    views = sum(n.kind == "view" for n in page.nodes)
    return tables, views, len(page.relations), len(page.notes)


def validate_foreign_key_annotations(pages: Iterable[Page]) -> dict[str, int]:
    """Fail generation when a textual FK annotation names an undefined table."""
    page_list = list(pages)
    table_nodes = [
        node
        for page in page_list
        for node in page.nodes
        if node.kind == "table"
    ]
    table_names = {node.name for node in table_nodes}
    duplicate_tables = sorted({name for name in table_names if sum(n.name == name for n in table_nodes) > 1})
    tables_without_pk = sorted(
        node.name for node in table_nodes
        if not any(field_value.startswith("PK ") for field_value in node.fields)
    )
    annotated_foreign_keys = 0
    malformed: list[str] = []
    missing: list[str] = []
    target_pattern = re.compile(r"->\s*([A-Za-z_][A-Za-z0-9_]*)")

    for page in page_list:
        for node in page.nodes:
            if node.kind != "table":
                continue
            for field_value in node.fields:
                targets = target_pattern.findall(field_value)
                if field_value.startswith("FK ") and not targets:
                    malformed.append(f"{node.name}: {field_value}")
                for target in targets:
                    annotated_foreign_keys += 1
                    if target not in table_names:
                        missing.append(f"{node.name} -> {target}")

    if duplicate_tables:
        raise ValueError("Duplicate table names: " + ", ".join(duplicate_tables))
    if tables_without_pk:
        raise ValueError("Tables without PK annotations: " + ", ".join(tables_without_pk))
    if malformed:
        raise ValueError("Malformed FK annotations: " + "; ".join(malformed))
    if missing:
        raise ValueError("Undefined FK targets: " + "; ".join(missing))
    return {
        "tables_defined": len(table_names),
        "duplicate_tables": 0,
        "tables_without_pk": 0,
        "annotated_foreign_keys": annotated_foreign_keys,
        "missing_fk_targets": 0,
    }


def generate(output: Path, pages: list[Page] | None = None) -> dict[str, int]:
    pages = build_pages() if pages is None else pages
    validate_foreign_key_annotations(pages)
    mxfile = ET.Element("mxfile", {
        "host": "app.diagrams.net", "modified": datetime.now(timezone.utc).isoformat(),
        "agent": "OpenAI Codex - Launch System ERD generator", "version": "24.7.17",
        "type": "device", "compressed": "false",
    })
    totals = {"pages": 0, "tables": 0, "views": 0, "edges": 0, "notes": 0}
    for i, page in enumerate(pages):
        diagram = ET.SubElement(mxfile, "diagram", {"id": f"launch-page-{i:02d}", "name": page.name})
        t, v, e, n = render_page(diagram, page, i)
        totals["pages"] += 1
        totals["tables"] += t
        totals["views"] += v
        totals["edges"] += e
        totals["notes"] += n

    tree = ET.ElementTree(mxfile)
    ET.indent(tree, space="  ")
    output.parent.mkdir(parents=True, exist_ok=True)
    tree.write(output, encoding="utf-8", xml_declaration=True)
    return totals


def validate(output: Path, expected_pages: int = 8) -> dict[str, int]:
    root = ET.parse(output).getroot()
    if root.tag != "mxfile":
        raise ValueError("Root must be mxfile")
    diagrams = root.findall("diagram")
    if len(diagrams) != expected_pages:
        raise ValueError(f"Expected {expected_pages} pages, found {len(diagrams)}")
    counts = {"pages": len(diagrams), "tables": 0, "views": 0, "edges": 0, "notes": 0}
    for diagram in diagrams:
        graph = diagram.find("mxGraphModel/root")
        if graph is None:
            raise ValueError(f"Page {diagram.get('name')} has no mxGraphModel/root")
        cells = graph.findall("mxCell")
        ids = {c.get("id") for c in cells}
        if not {"0", "1"}.issubset(ids):
            raise ValueError(f"Page {diagram.get('name')} lacks base cells")
        if len(ids) != len(cells):
            raise ValueError(f"Duplicate mxCell ids on page {diagram.get('name')}")
        for c in cells:
            kind = c.get("dataKind")
            if kind == "table": counts["tables"] += 1
            elif kind == "view": counts["views"] += 1
            elif kind == "note": counts["notes"] += 1
            if c.get("edge") == "1":
                counts["edges"] += 1
                if c.get("source") not in ids or c.get("target") not in ids:
                    raise ValueError(f"Dangling edge {c.get('id')} on page {diagram.get('name')}")
    return counts


def main() -> None:
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument("--output", type=Path, default=Path(__file__).with_name("launch_system_optimized.drawio"))
    args = parser.parse_args()
    pages = build_pages()
    fk_validation = validate_foreign_key_annotations(pages)
    generated = generate(args.output.resolve(), pages)
    validated = validate(args.output.resolve())
    if generated != validated:
        raise RuntimeError(f"Generated/validated counts differ: {generated} != {validated}")
    print(f"Wrote: {args.output.resolve()}")
    print("Validated XML: " + ", ".join(f"{k}={v}" for k, v in validated.items()))
    print("Validated FK annotations: " + ", ".join(f"{k}={v}" for k, v in fk_validation.items()))


if __name__ == "__main__":
    main()
